@startuml
title SeismicAttributeType Outgoing Relationships View

class "Reference Data Relationships" as RDR {
  <<reference-data>>
  "data.NameAlias[].AliasNameTypeID" → AliasNameType
  "data.NameAlias[].DefinitionOrganisationID" → StandardsOrganisation
}

class "SeismicAttributeType" as SAT {
  <<reference-data>>
}

class "AbstractReferenceType" as ART {
  <<Abstraction>>
}

class "NameAlias[]" as NA {
  <<nested array>>
}

class "Organisation" as Org {
  <<master-data>>
}

SAT --|> ART
SAT ..> RDR
SAT *-- NA
NA --> Org : DefinitionOrganisationID

SAT ..> RDR : "data.NameAlias[].AliasNameTypeID" → AliasNameType
SAT ..> RDR : "data.NameAlias[].DefinitionOrganisationID" → StandardsOrganisation

@enduml
